<?php
 declare(strict_types=1);
require_once __DIR__.'/training-campaign-data.php';
function tcl_slug(string $v): string{$s=strtolower(trim($v));$s=preg_replace('/[^a-z0-9]+/','-',$s)??$s;return trim($s,'-')?:'item';}
function tcl_public_id(): string{$d=random_bytes(16);$d[6]=chr((ord($d[6])&15)|64);$d[8]=chr((ord($d[8])&63)|128);$h=bin2hex($d);return substr($h,0,8).'-'.substr($h,8,4).'-'.substr($h,12,4).'-'.substr($h,16,4).'-'.substr($h,20);}
function tcl_now(): string{return date('Y-m-d H:i:s');}
function tcl_storage_config(): array{if(function_exists('lqr_config')){$c=lqr_config();return is_array($c)?$c:[];}$p=__DIR__.'/config.php';if(!is_file($p))$p=__DIR__.'/config.example.php';$c=require $p;return is_array($c)?$c:[];}
function tcl_storage_pdo(): ?PDO{static $pdo=null,$done=false;if($done)return $pdo;$done=true;$s=tcl_storage_config()['storage']??[];if(!is_array($s)||($s['driver']??'')!=='mysql'||empty($s['dsn']))return null;try{$o=is_array($s['options']??null)?$s['options']:[];$o[PDO::ATTR_ERRMODE]=PDO::ERRMODE_EXCEPTION;$o[PDO::ATTR_DEFAULT_FETCH_MODE]=PDO::FETCH_ASSOC;return $pdo=new PDO((string)$s['dsn'],(string)($s['username']??''),(string)($s['password']??''),$o);}catch(Throwable $e){return null;}}
function tcl_table(string $table): bool{$pdo=tcl_storage_pdo();if(!$pdo)return false;try{$st=$pdo->prepare('SHOW TABLES LIKE :t');$st->execute(['t'=>$table]);return (bool)$st->fetchColumn();}catch(Throwable $e){return false;}}
function tcl_storage_schema_available(): bool{return tcl_table('training_campaigns');}
function tcl_runtime_sql(): bool{return tcl_storage_schema_available()&&tcl_table('training_task_submissions')&&tcl_table('training_reviews');}
function tcl_storage_using_sql(): bool{return tcl_storage_schema_available();}
function tcl_normalize_campaign(array $c): array{$c['slug']=$c['slug']??$c['id']??tcl_slug((string)($c['title']??'campaign'));$c['id']=$c['id']??$c['slug'];$c['type']=strtolower((string)($c['type']??'general'));$c['sequence']['slug']=$c['sequence']['slug']??tcl_slug((string)($c['sequence']['title']??'sequence'));foreach(($c['sequence']['steps']??[]) as $i=>$step){$step['slug']=$step['slug']??tcl_slug((string)($step['title']??('task-'.$i)));$step['proof']=$step['proof']??'photo';$step['accepted_extensions']=$step['accepted_extensions']??'jpg,jpeg,png,webp,mp4,mov,webm';$step['max_file_size_mb']=$step['max_file_size_mb']??50;$step['is_required']=$step['is_required']??true;$c['sequence']['steps'][$i]=$step;}return $c;}
function tcl_storage_seed_campaigns(): array{return array_map('tcl_normalize_campaign',tcl_campaigns());}
function tcl_storage_campaigns(): array{if(!tcl_storage_schema_available())return tcl_storage_seed_campaigns();$pdo=tcl_storage_pdo();try{$rows=$pdo->query("SELECT * FROM training_campaigns WHERE status IN ('active','draft','paused','completed') ORDER BY title")->fetchAll();$out=[];foreach($rows as $r){$c=tcl_storage_normalize_campaign_row($r);$id=(int)$r['id'];$c['sequence_count']=tcl_storage_count_for_campaign('training_sequences',$id);$c['task_count']=tcl_storage_count_for_campaign('training_tasks',$id);$c['participant_count']=tcl_storage_count_for_campaign('training_participants',$id);$c['reward_ladder']=tcl_storage_reward_ladder($id);$c['sequence']=tcl_storage_first_sequence_bundle($id);$out[$c['slug']]=$c;}return $out?:tcl_storage_seed_campaigns();}catch(Throwable $e){return tcl_storage_seed_campaigns();}}
function tcl_storage_count_for_campaign(string $table,int $id): int{if(!in_array($table,['training_sequences','training_tasks','training_participants'],true))return 0;$pdo=tcl_storage_pdo();if(!$pdo)return 0;try{$s=$pdo->prepare("SELECT COUNT(*) FROM {$table} WHERE campaign_id=:id");$s->execute(['id'=>$id]);return (int)$s->fetchColumn();}catch(Throwable $e){return 0;}}
function tcl_storage_campaign_by_slug(string $slug): ?array{$all=tcl_storage_campaigns();return $all[$slug]??null;}
function tcl_storage_normalize_campaign_row(array $r): array{$m=[];if(!empty($r['metadata_json'])){$d=json_decode((string)$r['metadata_json'],true);if(is_array($d))$m=$d;}$tags=$m['tags']??[];if(!is_array($tags))$tags=[];return ['db_id'=>(int)$r['id'],'public_id'=>(string)$r['public_id'],'id'=>(string)$r['slug'],'slug'=>(string)$r['slug'],'title'=>(string)$r['title'],'eyebrow'=>(string)(($r['subtitle']??'')?:ucwords(str_replace('_',' ',(string)$r['campaign_type']))),'type'=>(string)$r['campaign_type'],'status'=>(string)$r['status'],'difficulty'=>(string)($r['difficulty']??'Standard'),'visibility'=>(string)$r['visibility'],'description'=>(string)$r['description'],'short_description'=>(string)$r['description'],'image_hint'=>strtoupper(substr((string)$r['campaign_type'],0,2)),'reward_preview'=>(string)($m['reward_preview']??'Reward configured'),'next_reward'=>(string)($m['next_reward']??($m['reward_preview']??'Next reward')),'sequence_count'=>0,'task_count'=>0,'participant_count'=>0,'duration'=>(string)($m['duration']??'Campaign'),'streak'=>(int)($m['streak']??0),'progress'=>(int)($m['progress']??0),'points'=>(int)($m['points']??0),'next_points'=>(int)($m['next_points']??0),'tags'=>array_values(array_map('strval',$tags)),'sequence'=>['slug'=>'sequence','title'=>'Sequence','description'=>'','steps'=>[]],'reward_ladder'=>[]];}
function tcl_storage_sequences(int $campaignId): array{$pdo=tcl_storage_pdo();if(!$pdo)return [];try{$s=$pdo->prepare('SELECT * FROM training_sequences WHERE campaign_id=:id ORDER BY sort_order,id');$s->execute(['id'=>$campaignId]);$out=[];foreach($s->fetchAll() as $r){$out[]=['db_id'=>(int)$r['id'],'public_id'=>(string)$r['public_id'],'slug'=>(string)$r['slug'],'title'=>(string)$r['title'],'description'=>(string)($r['description']??''),'status'=>(string)$r['status'],'is_required'=>(bool)$r['is_required'],'steps'=>tcl_storage_tasks((int)$r['id'])];}return $out;}catch(Throwable $e){return [];}}
function tcl_storage_first_sequence_bundle(int $campaignId): array{$s=tcl_storage_sequences($campaignId);return $s[0]??['slug'=>'sequence','title'=>'Sequence','description'=>'','steps'=>[]];}
function tcl_storage_tasks(int $sequenceId): array{$pdo=tcl_storage_pdo();if(!$pdo)return [];try{$s=$pdo->prepare('SELECT * FROM training_tasks WHERE sequence_id=:id ORDER BY sort_order,id');$s->execute(['id'=>$sequenceId]);$out=[];foreach($s->fetchAll() as $i=>$r){$out[]=['db_id'=>(int)$r['id'],'public_id'=>(string)$r['public_id'],'slug'=>(string)$r['slug'],'title'=>(string)$r['title'],'status'=>$i===0?'current':'locked','proof'=>(string)$r['proof_type'],'points'=>(int)$r['points'],'description'=>(string)($r['description']??''),'instructions'=>(string)($r['instructions']??''),'accepted_extensions'=>(string)($r['accepted_extensions']??''),'max_file_size_mb'=>$r['max_file_size_mb']===null?null:(int)$r['max_file_size_mb'],'is_required'=>(bool)$r['is_required']];}return $out;}catch(Throwable $e){return [];}}
function tcl_storage_reward_ladder(int $campaignId): array{$pdo=tcl_storage_pdo();if(!$pdo)return [];try{$s=$pdo->prepare('SELECT * FROM training_reward_rules WHERE campaign_id=:id ORDER BY sort_order,id');$s->execute(['id'=>$campaignId]);$out=[];foreach($s->fetchAll() as $i=>$r){$out[]=['db_id'=>(int)$r['id'],'public_id'=>(string)$r['public_id'],'label'=>(string)$r['title'],'requirement'=>'Complete '.number_format((int)$r['required_completions']).' sequence','reward'=>(string)$r['reward_label'],'status'=>$i===0?'current':'locked','trigger_type'=>(string)$r['trigger_type'],'reward_type'=>(string)$r['reward_type'],'reward_value_cents'=>(int)$r['reward_value_cents']];}return $out;}catch(Throwable $e){return [];}}
function tcl_storage_summary(array $campaigns): array{$a=0;$p=0;$t=0;$pr=0;foreach($campaigns as $c){if(($c['status']??'')==='active')$a++;$p+=(int)($c['participant_count']??0);$t+=(int)($c['task_count']??0);$pr+=(int)($c['progress']??0);}return ['active_campaigns'=>$a,'total_participants'=>$p,'total_tasks'=>$t,'average_progress'=>$campaigns?(int)round($pr/max(1,count($campaigns))):0,'source'=>tcl_storage_using_sql()?'sql':'seed'];}
function tcl_campaign_row(string $slug): ?array{$pdo=tcl_storage_pdo();if(!$pdo)return null;$s=$pdo->prepare('SELECT * FROM training_campaigns WHERE slug=:s LIMIT 1');$s->execute(['s'=>$slug]);$r=$s->fetch();return $r?:null;}
function tcl_sequence_row(int $campaignId,string $slug=''): ?array{$pdo=tcl_storage_pdo();$sql=$slug!==''?'SELECT * FROM training_sequences WHERE campaign_id=:c AND slug=:s LIMIT 1':'SELECT * FROM training_sequences WHERE campaign_id=:c ORDER BY sort_order,id LIMIT 1';$s=$pdo->prepare($sql);$args=['c'=>$campaignId];if($slug!=='')$args['s']=$slug;$s->execute($args);$r=$s->fetch();return $r?:null;}
function tcl_task_row(int $campaignId,string $slug): ?array{$pdo=tcl_storage_pdo();$s=$pdo->prepare('SELECT * FROM training_tasks WHERE campaign_id=:c AND slug=:s LIMIT 1');$s->execute(['c'=>$campaignId,'s'=>$slug]);$r=$s->fetch();return $r?:null;}
function tcl_state_path(): string{return __DIR__.'/data/training_lab_state.json';}
function tcl_default_state(): array{return ['participants'=>[],'submissions'=>[],'reviews'=>[],'receipts'=>[],'reward_issues'=>[],'events'=>[],'updated_at'=>tcl_now()];}
function tcl_state_load(): array{$p=tcl_state_path();if(!is_file($p))return tcl_default_state();$d=json_decode((string)file_get_contents($p),true);return is_array($d)?array_replace_recursive(tcl_default_state(),$d):tcl_default_state();}
function tcl_state_save(array $s): void{$dir=dirname(tcl_state_path());if(!is_dir($dir))@mkdir($dir,0775,true);$s['updated_at']=tcl_now();file_put_contents(tcl_state_path(),json_encode($s,JSON_PRETTY_PRINT|JSON_UNESCAPED_SLASHES));}
function tcl_event(array &$s,string $type,string $message,array $ctx=[]): void{if(tcl_runtime_sql())try{$pdo=tcl_storage_pdo();$st=$pdo->prepare('INSERT INTO training_events(public_id,event_type,actor_user_id,actor_role,campaign_id,participant_id,target_type,target_id,status_before,status_after,metadata_json) VALUES(:p,:e,:a,:r,NULL,NULL,:tt,:ti,:sb,:sa,:m)');$st->execute(['p'=>tcl_public_id(),'e'=>$type,'a'=>(string)($ctx['user_id']??''),'r'=>(string)($ctx['role']??''),'tt'=>(string)($ctx['target_type']??''),'ti'=>(string)($ctx['target_id']??''),'sb'=>(string)($ctx['before']??''),'sa'=>(string)($ctx['after']??''),'m'=>json_encode($ctx)]);return;}catch(Throwable $e){} array_unshift($s['events'],['id'=>tcl_public_id(),'at'=>tcl_now(),'type'=>$type,'message'=>$message,'context'=>$ctx]);$s['events']=array_slice($s['events'],0,250);}
function tcl_participant_key(string $campaignSlug,string $userId): string{return $campaignSlug.'|'.$userId;}
function tcl_get_participant(string $campaignSlug,string $userId): ?array{if(tcl_runtime_sql()){try{$c=tcl_campaign_row($campaignSlug);if(!$c)return null;$pdo=tcl_storage_pdo();$s=$pdo->prepare('SELECT * FROM training_participants WHERE campaign_id=:c AND user_id=:u LIMIT 1');$s->execute(['c'=>$c['id'],'u'=>$userId]);$r=$s->fetch();return $r?['id'=>(string)$r['id'],'public_id'=>(string)$r['public_id'],'campaign_slug'=>$campaignSlug,'user_id'=>(string)$r['user_id'],'display_name'=>(string)$r['display_name'],'email'=>(string)$r['email'],'status'=>(string)$r['status'],'joined_at'=>(string)$r['joined_at'],'completed_at'=>(string)($r['completed_at']??'')]:null;}catch(Throwable $e){}}$s=tcl_state_load();return $s['participants'][tcl_participant_key($campaignSlug,$userId)]??null;}
function tcl_join_campaign(string $campaignSlug,array $user): array{if(tcl_runtime_sql()){try{$c=tcl_campaign_row($campaignSlug);if(!$c)throw new RuntimeException('Campaign not found.');$pdo=tcl_storage_pdo();$existing=tcl_get_participant($campaignSlug,(string)$user['id']);if($existing)return $existing;$st=$pdo->prepare("INSERT INTO training_participants(public_id,campaign_id,user_id,external_user_id,display_name,email,role,status) VALUES(:p,:c,:u,:x,:n,:e,'participant','active')");$st->execute(['p'=>tcl_public_id(),'c'=>$c['id'],'u'=>(string)$user['id'],'x'=>(string)($user['external_user_id']??''),'n'=>(string)($user['display_name']??'Participant'),'e'=>(string)($user['email']??'')]);$tmp=[];tcl_event($tmp,'training.campaign.joined','Participant joined campaign.',['campaign'=>$campaignSlug,'user_id'=>(string)$user['id']]);return tcl_get_participant($campaignSlug,(string)$user['id']);}catch(Throwable $e){throw $e;}}$campaign=tcl_storage_campaign_by_slug($campaignSlug);if(!$campaign)throw new RuntimeException('Campaign not found.');$s=tcl_state_load();$key=tcl_participant_key($campaignSlug,(string)$user['id']);if(empty($s['participants'][$key])){$s['participants'][$key]=['id'=>tcl_public_id(),'campaign_slug'=>$campaignSlug,'user_id'=>(string)$user['id'],'display_name'=>(string)($user['display_name']??'Participant'),'email'=>(string)($user['email']??''),'status'=>'active','joined_at'=>tcl_now(),'completed_at'=>null];tcl_event($s,'training.campaign.joined','Participant joined campaign.',['campaign'=>$campaignSlug,'user_id'=>(string)$user['id']]);tcl_state_save($s);}return $s['participants'][$key];}
function tcl_participant_required(string $campaignSlug,array $user): array{$p=tcl_get_participant($campaignSlug,(string)($user['id']??''));if(!$p)throw new RuntimeException('Join this campaign before continuing.');return $p;}
function tcl_submissions_for_participant(string $participantId,string $campaignSlug=''): array{if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();$sql='SELECT s.*,c.slug campaign_slug,t.slug task_slug,q.slug sequence_slug,f.original_filename,f.stored_filename,f.storage_path FROM training_task_submissions s JOIN training_campaigns c ON c.id=s.campaign_id JOIN training_tasks t ON t.id=s.task_id JOIN training_sequences q ON q.id=s.sequence_id LEFT JOIN training_files f ON f.id=s.file_id WHERE s.participant_id=:p';$args=['p'=>(int)$participantId];if($campaignSlug!==''){$sql.=' AND c.slug=:c';$args['c']=$campaignSlug;}$sql.=' ORDER BY s.submitted_at DESC';$st=$pdo->prepare($sql);$st->execute($args);$out=[];foreach($st->fetchAll() as $r)$out[]=['id'=>(string)$r['public_id'],'sql_id'=>(int)$r['id'],'participant_id'=>(string)$r['participant_id'],'campaign_slug'=>(string)$r['campaign_slug'],'sequence_slug'=>(string)$r['sequence_slug'],'task_slug'=>(string)$r['task_slug'],'attempt_number'=>(int)$r['attempt_number'],'participant_note'=>(string)$r['participant_note'],'status'=>(string)$r['status'],'submitted_at'=>(string)$r['submitted_at'],'reviewed_at'=>(string)($r['reviewed_at']??''),'file'=>['original_filename'=>(string)($r['original_filename']??''),'stored_filename'=>(string)($r['stored_filename']??''),'storage_path'=>(string)($r['storage_path']??'')]];return $out;}catch(Throwable $e){return [];}}$s=tcl_state_load();return array_values(array_filter($s['submissions'],fn($x)=>($x['participant_id']??'')===$participantId&&($campaignSlug===''||($x['campaign_slug']??'')===$campaignSlug)));}
function tcl_latest_submission_for_task(string $participantId,string $campaignSlug,string $taskSlug): ?array{$subs=tcl_submissions_for_participant($participantId,$campaignSlug);$subs=array_values(array_filter($subs,fn($x)=>($x['task_slug']??'')===$taskSlug));return $subs[0]??null;}
function tcl_progress(string $campaignSlug,array $user): array{$campaign=tcl_storage_campaign_by_slug($campaignSlug);$p=tcl_get_participant($campaignSlug,(string)($user['id']??''));$steps=(array)($campaign['sequence']['steps']??[]);$approved=0;$pending=0;$needs=0;$total=0;$out=[];foreach($steps as $i=>$step){$step['slug']=$step['slug']??tcl_slug((string)($step['title']??('task-'.$i)));if(!($step['is_required']??true))continue;$total++;$latest=$p?tcl_latest_submission_for_task((string)$p['id'],$campaignSlug,(string)$step['slug']):null;$status=$latest['status']??($i===0?'current':'locked');if($status==='approved')$approved++;elseif($status==='pending_review')$pending++;elseif(in_array($status,['needs_resubmission','rejected'],true))$needs++;$step['status']=$status;$step['submission']=$latest;$out[]=$step;}return ['joined'=>(bool)$p,'participant'=>$p,'total'=>$total,'approved'=>$approved,'pending'=>$pending,'needs_action'=>$needs,'percent'=>$total?(int)floor(($approved/$total)*100):0,'complete'=>$total>0&&$approved>=$total,'steps'=>$out];}
function tcl_save_submission(array $participant,string $campaignSlug,string $sequenceSlug,string $taskSlug,array $file,array $note=[]): array{if(tcl_runtime_sql()){try{$c=tcl_campaign_row($campaignSlug);$q=tcl_sequence_row((int)$c['id'],$sequenceSlug)?:tcl_sequence_row((int)$c['id']);$t=tcl_task_row((int)$c['id'],$taskSlug);if(!$c||!$q||!$t)throw new RuntimeException('Campaign task not found.');$pdo=tcl_storage_pdo();$pdo->beginTransaction();$fileId=null;if($file){$fs=$pdo->prepare("INSERT INTO training_files(public_id,uploaded_by_user_id,participant_id,original_filename,stored_filename,storage_path,file_extension,mime_type,file_size_bytes,status) VALUES(:p,:u,:pt,:o,:sf,:sp,:x,:m,:b,'attached')");$fs->execute(['p'=>tcl_public_id(),'u'=>(string)$participant['user_id'],'pt'=>(int)$participant['id'],'o'=>(string)($file['original_filename']??''),'sf'=>(string)($file['stored_filename']??''),'sp'=>(string)($file['storage_path']??''),'x'=>(string)($file['file_extension']??''),'m'=>(string)($file['mime_type']??''),'b'=>(int)($file['file_size_bytes']??0)]);$fileId=(int)$pdo->lastInsertId();}$a=$pdo->prepare('SELECT COALESCE(MAX(attempt_number),0)+1 FROM training_task_submissions WHERE participant_id=:p AND task_id=:t');$a->execute(['p'=>(int)$participant['id'],'t'=>$t['id']]);$attempt=(int)$a->fetchColumn();$pub=tcl_public_id();$ss=$pdo->prepare("INSERT INTO training_task_submissions(public_id,campaign_id,sequence_id,task_id,participant_id,file_id,attempt_number,participant_note,status) VALUES(:pub,:c,:q,:t,:p,:f,:a,:n,'pending_review')");$ss->execute(['pub'=>$pub,'c'=>$c['id'],'q'=>$q['id'],'t'=>$t['id'],'p'=>(int)$participant['id'],'f'=>$fileId,'a'=>$attempt,'n'=>(string)($note['participant_note']??'')]);$pdo->commit();$tmp=[];tcl_event($tmp,'training.proof.uploaded','Proof submitted for review.',['campaign'=>$campaignSlug,'task'=>$taskSlug,'submission_id'=>$pub]);return ['id'=>$pub,'participant_id'=>(string)$participant['id'],'campaign_slug'=>$campaignSlug,'sequence_slug'=>(string)$q['slug'],'task_slug'=>$taskSlug,'file'=>$file,'attempt_number'=>$attempt,'participant_note'=>(string)($note['participant_note']??''),'status'=>'pending_review','submitted_at'=>tcl_now(),'reviewed_at'=>null];}catch(Throwable $e){if(isset($pdo)&&$pdo->inTransaction())$pdo->rollBack();throw $e;}}$s=tcl_state_load();$attempt=1;foreach($s['submissions'] as $sub){if(($sub['participant_id']??'')===$participant['id']&&($sub['campaign_slug']??'')===$campaignSlug&&($sub['task_slug']??'')===$taskSlug)$attempt=max($attempt,((int)($sub['attempt_number']??1))+1);}$sub=['id'=>tcl_public_id(),'participant_id'=>$participant['id'],'user_id'=>(string)($participant['user_id']??''),'campaign_slug'=>$campaignSlug,'sequence_slug'=>$sequenceSlug,'task_slug'=>$taskSlug,'file'=>$file,'attempt_number'=>$attempt,'participant_note'=>(string)($note['participant_note']??''),'status'=>'pending_review','submitted_at'=>tcl_now(),'reviewed_at'=>null];$s['submissions'][$sub['id']]=$sub;tcl_event($s,'training.proof.uploaded','Proof submitted for review.',['campaign'=>$campaignSlug,'task'=>$taskSlug,'submission_id'=>$sub['id']]);tcl_state_save($s);return $sub;}
function tcl_pending_submissions(): array{if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();$st=$pdo->query("SELECT s.*,c.slug campaign_slug,t.slug task_slug,q.slug sequence_slug,f.original_filename FROM training_task_submissions s JOIN training_campaigns c ON c.id=s.campaign_id JOIN training_tasks t ON t.id=s.task_id JOIN training_sequences q ON q.id=s.sequence_id LEFT JOIN training_files f ON f.id=s.file_id WHERE s.status='pending_review' ORDER BY s.submitted_at DESC");$out=[];foreach($st->fetchAll() as $r)$out[]=['id'=>(string)$r['public_id'],'sql_id'=>(int)$r['id'],'participant_id'=>(string)$r['participant_id'],'campaign_slug'=>(string)$r['campaign_slug'],'sequence_slug'=>(string)$r['sequence_slug'],'task_slug'=>(string)$r['task_slug'],'attempt_number'=>(int)$r['attempt_number'],'participant_note'=>(string)$r['participant_note'],'status'=>(string)$r['status'],'submitted_at'=>(string)$r['submitted_at'],'file'=>['original_filename'=>(string)($r['original_filename']??'')]];return $out;}catch(Throwable $e){return [];}}$s=tcl_state_load();return array_values(array_filter($s['submissions'],fn($x)=>($x['status']??'')==='pending_review'));}
function tcl_get_submission_by_public(string $id): ?array{$all=tcl_pending_submissions();foreach($all as $s)if(($s['id']??'')===$id)return $s;if(!tcl_runtime_sql()){foreach(tcl_state_load()['submissions'] as $s)if(($s['id']??'')===$id)return $s;}return null;}
function tcl_review_submission(string $submissionId,string $decision,string $note,array $reviewer): array{if(!in_array($decision,['approved','rejected','needs_resubmission'],true))throw new RuntimeException('Invalid review decision.');if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();$st=$pdo->prepare('SELECT * FROM training_task_submissions WHERE public_id=:p LIMIT 1');$st->execute(['p'=>$submissionId]);$sub=$st->fetch();if(!$sub)throw new RuntimeException('Submission not found.');$sqlDecision=$decision==='needs_resubmission'?'resubmission_requested':$decision;$pdo->beginTransaction();$rv=$pdo->prepare('INSERT INTO training_reviews(public_id,submission_id,campaign_id,participant_id,reviewer_user_id,reviewer_role,decision,reviewer_note) VALUES(:pub,:s,:c,:p,:u,:r,:d,:n)');$reviewPub=tcl_public_id();$rv->execute(['pub'=>$reviewPub,'s'=>$sub['id'],'c'=>$sub['campaign_id'],'p'=>$sub['participant_id'],'u'=>(string)($reviewer['id']??'admin'),'r'=>'reviewer','d'=>$sqlDecision,'n'=>$note]);$up=$pdo->prepare('UPDATE training_task_submissions SET status=:d, reviewed_at=NOW() WHERE id=:id');$up->execute(['d'=>$decision,'id'=>$sub['id']]);$pdo->commit();$tmp=[];tcl_event($tmp,'training.review.'.$decision,'Submission reviewed.',['target_id'=>$submissionId,'before'=>$sub['status'],'after'=>$decision]);if($decision==='approved'&&function_exists('tcl_create_receipts_for_submission')){tcl_create_receipts_for_submission($submissionId);if(function_exists('tcl_evaluate_rewards_for_submission'))tcl_evaluate_rewards_for_submission($submissionId);}return ['id'=>$reviewPub,'submission_id'=>$submissionId,'decision'=>$decision,'reviewer_note'=>$note,'reviewed_at'=>tcl_now()];}catch(Throwable $e){if(isset($pdo)&&$pdo->inTransaction())$pdo->rollBack();throw $e;}}$s=tcl_state_load();if(empty($s['submissions'][$submissionId]))throw new RuntimeException('Submission not found.');$before=$s['submissions'][$submissionId]['status'];$s['submissions'][$submissionId]['status']=$decision;$s['submissions'][$submissionId]['reviewed_at']=tcl_now();$review=['id'=>tcl_public_id(),'submission_id'=>$submissionId,'decision'=>$decision,'reviewer_user_id'=>(string)($reviewer['id']??'admin'),'reviewer_name'=>(string)($reviewer['display_name']??'Reviewer'),'reviewer_note'=>$note,'reviewed_at'=>tcl_now()];$s['reviews'][$review['id']]=$review;tcl_event($s,'training.review.'.$decision,'Submission reviewed.',['submission_id'=>$submissionId,'before'=>$before,'after'=>$decision]);tcl_state_save($s);if($decision==='approved'&&function_exists('tcl_create_receipts_for_submission')){tcl_create_receipts_for_submission($submissionId);if(function_exists('tcl_evaluate_rewards_for_submission'))tcl_evaluate_rewards_for_submission($submissionId);}return $review;}
function tcl_receipts_for_participant(string $participantId): array{if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();$st=$pdo->prepare('SELECT * FROM training_action_receipts WHERE participant_id=:p ORDER BY created_at DESC');$st->execute(['p'=>(int)$participantId]);return array_map(fn($r)=>['id'=>(string)$r['public_id'],'receipt_type'=>(string)$r['receipt_type'],'participant_id'=>(string)$r['participant_id'],'campaign_slug'=>'','sequence_slug'=>'','task_slug'=>'','submission_id'=>(string)($r['submission_id']??''),'status'=>(string)$r['status'],'points_awarded'=>(int)$r['points_awarded'],'created_at'=>(string)$r['created_at']],$st->fetchAll());}catch(Throwable $e){return [];}}$s=tcl_state_load();return array_values(array_filter($s['receipts'],fn($x)=>($x['participant_id']??'')===$participantId));}
function tcl_reward_issues_for_participant(string $participantId): array{if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();$st=$pdo->prepare('SELECT * FROM training_reward_issues WHERE participant_id=:p ORDER BY created_at DESC');$st->execute(['p'=>(int)$participantId]);return array_map(fn($r)=>['id'=>(string)$r['public_id'],'participant_id'=>(string)$r['participant_id'],'campaign_slug'=>'','receipt_id'=>(string)$r['receipt_id'],'reward_label'=>'Training Reward','status'=>(string)$r['status'],'failure_reason'=>(string)($r['failure_reason']??''),'created_at'=>(string)$r['created_at']],$st->fetchAll());}catch(Throwable $e){return [];}}$s=tcl_state_load();return array_values(array_filter($s['reward_issues'],fn($x)=>($x['participant_id']??'')===$participantId));}
function tcl_all_receipts(): array{if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();return $pdo->query('SELECT *, public_id id FROM training_action_receipts ORDER BY created_at DESC')->fetchAll();}catch(Throwable $e){return [];}}$s=tcl_state_load();return array_values($s['receipts']);}
function tcl_all_reward_issues(): array{if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();return $pdo->query('SELECT *, public_id id FROM training_reward_issues ORDER BY created_at DESC')->fetchAll();}catch(Throwable $e){return [];}}$s=tcl_state_load();return array_values($s['reward_issues']);}
function tcl_training_events(): array{if(tcl_runtime_sql()){try{$pdo=tcl_storage_pdo();$rows=$pdo->query('SELECT * FROM training_events ORDER BY created_at DESC LIMIT 250')->fetchAll();return array_map(fn($r)=>['id'=>(string)$r['public_id'],'at'=>(string)$r['created_at'],'type'=>(string)$r['event_type'],'message'=>(string)$r['event_type'],'context'=>json_decode((string)($r['metadata_json']??'{}'),true)?:[]],$rows);}catch(Throwable $e){return [];}}$s=tcl_state_load();return $s['events'];}
